import{_ as e,o as r,c as d,ag as o}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"User Federation","description":"","frontmatter":{},"headers":[],"relativePath":"admin-ui/user-federation.md","filePath":"admin-ui/user-federation.md"}'),n={name:"admin-ui/user-federation.md"};function i(a,t,s,c,l,h){return r(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="user-federation" tabindex="-1">User Federation <a class="header-anchor" href="#user-federation" aria-label="Permalink to &quot;User Federation&quot;">​</a></h1><p>User Federation manages LDAP directory connections for importing and synchronizing users into Keycloak. This is found as a sub-tab within the <strong>Users</strong> admin page.</p><h2 id="accessing" tabindex="-1">Accessing <a class="header-anchor" href="#accessing" aria-label="Permalink to &quot;Accessing&quot;">​</a></h2><p>Navigate to <strong>Users</strong> in the admin sidebar, then select the <strong>User Federation</strong> tab.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><h3 id="provider-list" tabindex="-1">Provider List <a class="header-anchor" href="#provider-list" aria-label="Permalink to &quot;Provider List&quot;">​</a></h3><p>Displays all configured LDAP federation providers with:</p><ul><li>Provider name and connection URL</li><li>Sync status and last sync time</li><li>User count (imported users)</li><li>Enabled/disabled status</li></ul><h3 id="adding-an-ldap-provider" tabindex="-1">Adding an LDAP Provider <a class="header-anchor" href="#adding-an-ldap-provider" aria-label="Permalink to &quot;Adding an LDAP Provider&quot;">​</a></h3><p>Click <strong>Add Provider</strong> to configure a new LDAP connection:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Display name for the federation provider</td></tr><tr><td><strong>Vendor</strong></td><td>LDAP vendor (Active Directory, OpenLDAP, Red Hat DS, etc.)</td></tr><tr><td><strong>Connection URL</strong></td><td>LDAP server URL (<code>ldap://</code> or <code>ldaps://</code>)</td></tr><tr><td><strong>Bind DN</strong></td><td>Distinguished name for binding to LDAP</td></tr><tr><td><strong>Bind Credential</strong></td><td>Password for the bind DN</td></tr><tr><td><strong>Users DN</strong></td><td>Base DN for user searches</td></tr><tr><td><strong>User Object Classes</strong></td><td>LDAP object classes for user entries</td></tr><tr><td><strong>Edit Mode</strong></td><td>How Keycloak writes back to LDAP (<code>READ_ONLY</code>, <code>WRITABLE</code>, <code>UNSYNCED</code>)</td></tr><tr><td><strong>Search Scope</strong></td><td>LDAP search scope (<code>ONE_LEVEL</code> or <code>SUBTREE</code>)</td></tr><tr><td><strong>Pagination</strong></td><td>Enable LDAP pagination for large directories</td></tr><tr><td><strong>Import Users</strong></td><td>Whether to import users into Keycloak&#39;s local database</td></tr><tr><td><strong>Sync Registrations</strong></td><td>Sync newly registered Keycloak users back to LDAP</td></tr></tbody></table><h3 id="connection-testing" tabindex="-1">Connection Testing <a class="header-anchor" href="#connection-testing" aria-label="Permalink to &quot;Connection Testing&quot;">​</a></h3><p>Before saving, you can test the LDAP connection:</p><ul><li><strong>Test Connection</strong> — Verifies network connectivity and TLS handshake</li><li><strong>Test Authentication</strong> — Verifies bind credentials are accepted</li></ul><h3 id="synchronization" tabindex="-1">Synchronization <a class="header-anchor" href="#synchronization" aria-label="Permalink to &quot;Synchronization&quot;">​</a></h3><p>Once configured, synchronize users from LDAP:</p><ul><li><strong>Full Sync</strong> — Import all users matching the filter</li><li><strong>Changed Users Sync</strong> — Import only users modified since the last sync</li><li><strong>Remove Imported</strong> — Remove all users imported from this provider</li><li><strong>Unlink Users</strong> — Unlink imported users from the federation provider (keeps the users)</li></ul><h3 id="mapper-configuration" tabindex="-1">Mapper Configuration <a class="header-anchor" href="#mapper-configuration" aria-label="Permalink to &quot;Mapper Configuration&quot;">​</a></h3><p>Each provider can have attribute mappers that control how LDAP attributes map to Keycloak user attributes. View the mapper list for any provider to see:</p><ul><li>Mapper name and type</li><li>LDAP attribute → Keycloak attribute mapping</li><li>Read/write synchronization direction</li></ul><h2 id="api-endpoints" tabindex="-1">API Endpoints <a class="header-anchor" href="#api-endpoints" aria-label="Permalink to &quot;API Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/user-federation/count</code></td><td>Count federation providers</td></tr><tr><td><code>GET</code></td><td><code>/admin/user-federation/</code></td><td>List all providers</td></tr><tr><td><code>POST</code></td><td><code>/admin/user-federation/</code></td><td>Create a new LDAP provider</td></tr><tr><td><code>GET</code></td><td><code>/admin/user-federation/:id</code></td><td>Get provider details</td></tr><tr><td><code>PUT</code></td><td><code>/admin/user-federation/:id</code></td><td>Update provider configuration</td></tr><tr><td><code>DELETE</code></td><td><code>/admin/user-federation/:id</code></td><td>Delete a provider</td></tr><tr><td><code>POST</code></td><td><code>/admin/user-federation/:id/sync</code></td><td>Trigger user sync (query: <code>action=triggerFullSync</code> or <code>triggerChangedUsersSync</code>)</td></tr><tr><td><code>POST</code></td><td><code>/admin/user-federation/:id/remove-imported</code></td><td>Remove all imported users</td></tr><tr><td><code>POST</code></td><td><code>/admin/user-federation/:id/unlink</code></td><td>Unlink users from provider</td></tr><tr><td><code>POST</code></td><td><code>/admin/user-federation/test-connection</code></td><td>Test LDAP connectivity</td></tr><tr><td><code>POST</code></td><td><code>/admin/user-federation/test-authentication</code></td><td>Test bind credentials</td></tr><tr><td><code>GET</code></td><td><code>/admin/user-federation/:id/mappers</code></td><td>List attribute mappers</td></tr></tbody></table>',22)])])}const g=e(n,[["render",i]]);export{p as __pageData,g as default};
